#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N, M, x, y, a, b;
        scanf("%lld %lld", &N, &M);
        scanf("%lld %lld", &x, &y);
        scanf("%lld %lld", &a, &b);
        long long thief = (N - x) + (M - y);
        long long police = (N - a > M - b) ? (N - a) : (M - b);
        if (police >= thief) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

